  {
   "id": "C-018",
   "title": "ISSUE_006: Notes Phase I failed to classify the buried drum",
   "match_criteria": "PASS if the memo notes that the Phase I ESA mentions the drum in the site reconnaissance section but fails to classify it as a REC, CREC, HREC, or data gap. FAIL if the memo does not note this classification omission in the Phase I."
  },
  {
   "id": "C-019",
   "title": "ISSUE_006: Notes drum location is outside the 2011 NFA area",
